import multerErrorMap from "../constants/multer.error.map.js";
import prismaErrorMap from "../constants/prisma.error.map.js";

// generate error props for errors generated by other services
const getErrorProps = (err) => {

    const errProps = {
        errorName: err.name || 'Error',
        isOperational: err.isOperational || false,
        statusCode: err.statusCode || 500,
        message: err.message || 'Something went wrong! Please try again later.',
        prodMessage: '',
        stack: err.stack,
    }

    // for prisma errors
    if (err.name === 'PrismaClientKnownRequestError' &&
        err.code &&
        prismaErrorMap[err.code]) {

        const prismaError = prismaErrorMap[err.code];
        errProps.statusCode = prismaError.statusCode;
        errProps.prodMessage = prismaError.message(err);
        errProps.isOperational = true;
    }

    // for multer errors
    if(multerErrorMap[err.code]){
        errProps.statusCode = multerErrorMap[err.code].statusCode;
        errProps.prodMessage = multerErrorMap[err.code].message(err);
        errProps.isOperational = true;
    }

    return errProps;
}

// middleware called by express whenever passed an arg in next() function
function GlobalErrorHandler (err, req, res, next){
console.log('Error catched by GlobalErrorHandler:', err);

// get error properties (errorName, errorMessage, etc)
    const errProps = getErrorProps(err)

    // dev error
    if (process.env.NODE_ENV === 'development')
    return res.status(errProps.statusCode).json(errProps)

    // production error
    else {
        const statusCode = errProps.statusCode;
        const message = errProps.prodMessage || errProps.message;

        // return err response in production mode
        res.status(statusCode).json({
            status: 'fail',
            message
        })
    }
}

export default GlobalErrorHandler;